import { useState } from "react";
import Sidebar from "../components/Sidebar";
import KnowledgeBaseForm from "../components/KnowledgeBaseForm";
import BannedPhrasesManager from "../components/BannedPhrasesManager";
import ActionTypesManager from "../components/ActionTypesManager";
import AgentActionsFeed from "../components/AgentActionsFeed";
import FlagsFeed from "../components/FlagsFeed";

const TABS = [
  { id: "kb", label: "Knowledge Base" },
  { id: "phrases", label: "Banned Phrases" },
  { id: "actions", label: "Action Types" },
  { id: "feeds", label: "Live Feeds" },
];

export default function TeamLeadDashboard() {
  const [activeTab, setActiveTab] = useState("kb");

  return (
    <div className="min-h-screen bg-surface-bg flex">
      <Sidebar />

      <main className="flex-1 ml-[260px] p-8 md:p-10">
        <div className="max-w-6xl mx-auto">
          <header className="mb-10">
            <h1 className="text-[32px] leading-[40px] font-semibold text-slate-900 mb-2">
              Dashboard
            </h1>
            <p className="text-semantic-neutral text-base">
              Manage knowledge base content, compliance rules, and monitor agent activity.
            </p>
          </header>

          <section className="grid grid-cols-1 lg:grid-cols-3 gap-6 mb-8">
            <div className="lg:col-span-2 bg-surface-card p-6 md:p-8 rounded-2xl shadow-card border border-surface-border">
              <h2 className="text-[24px] font-semibold text-slate-900 mb-2">Knowledge Base</h2>
              <p className="text-semantic-neutral mb-6 text-sm">
                Add, edit, or remove policies and support guidance.
              </p>
              <button
                type="button"
                onClick={() => setActiveTab("kb")}
                className="bg-brand-primary hover:bg-brand-light text-white font-medium py-2.5 px-6 rounded-xl transition-colors"
              >
                + Add New Policy
              </button>
            </div>

            <div className="bg-surface-card p-6 md:p-8 rounded-2xl shadow-card border border-surface-border">
              <h2 className="text-[20px] font-medium text-slate-900 mb-4">Quick Stats</h2>
              <div className="flex items-center gap-4 p-4 bg-brand-faint rounded-xl mb-3">
                <div className="w-10 h-10 rounded-full bg-white flex items-center justify-center text-brand-primary font-bold">
                  {TABS.length}
                </div>
                <span className="text-sm font-medium text-brand-primary">Management Areas</span>
              </div>
              <p className="text-sm text-semantic-neutral">
                Active tools for policies, phrases, actions, and live monitoring.
              </p>
            </div>
          </section>

          <div className="flex flex-wrap gap-2 mb-6 p-1.5 bg-white rounded-2xl shadow-sm border border-surface-border">
            {TABS.map((tab) => (
              <button
                key={tab.id}
                type="button"
                onClick={() => setActiveTab(tab.id)}
                className={`tab-btn ${
                  activeTab === tab.id ? "tab-btn-active" : "tab-btn-inactive"
                }`}
              >
                {tab.label}
              </button>
            ))}
          </div>

          {activeTab === "kb" && <KnowledgeBaseForm />}
          {activeTab === "phrases" && <BannedPhrasesManager />}
          {activeTab === "actions" && <ActionTypesManager />}
          {activeTab === "feeds" && (
            <div className="grid grid-cols-1 xl:grid-cols-2 gap-6">
              <FlagsFeed />
              <AgentActionsFeed />
            </div>
          )}
        </div>
      </main>
    </div>
  );
}
